SELECT COUNT(*) FROM PRODUCT
AND (product_name LIKE CONCAT('%', #{searchKeyword}, '%') OR product_code LIKE CONCAT('%', #{searchKeyword}, '%'))
AND category = #{searchCategory}

SELECT s.so_id, s.so_no, s.customer_id, c.customer_name, DATE_FORMAT(s.order_date, '%Y-%m-%d') AS order_date, DATE_FORMAT(s.delivery_date, '%Y-%m-%d') AS delivery_date, s.status, s.created_by, DATE_FORMAT(s.created_at, '%Y-%m-%d') AS created_at FROM SALES_ORDER s LEFT JOIN CUSTOMER c ON s.customer_id = c.customer_id
AND (c.customer_name LIKE CONCAT('%', #{searchKeyword}, '%') OR s.so_no LIKE CONCAT('%', #{searchKeyword}, '%'))
AND s.status = #{searchStatus}
AND s.order_date >= #{dateFrom}
AND s.order_date <= #{dateTo}
ORDER BY s.created_at DESC

SELECT COUNT(*)
FROM   SALES_ORDER s
LEFT JOIN CUSTOMER c ON s.customer_id = c.customer_id


        AND (c.customer_name LIKE CONCAT('%', #{searchKeyword}, '%')
          OR s.so_no         LIKE CONCAT('%', #{searchKeyword}, '%'))


        AND s.status = #{searchStatus}


        AND s.order_date >= #{dateFrom}


        AND s.order_date <= #{dateTo}

SELECT COUNT(*) FROM PRODUCT p LEFT JOIN INVENTORY i ON p.product_id = i.product_id
AND (p.product_name LIKE CONCAT('%', #{searchKeyword}, '%') OR p.product_code LIKE CONCAT('%', #{searchKeyword}, '%'))
AND p.category = #{searchCategory}

